{!REQUIRESCRIPT("/soap/ajax/48.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/48.0/apex.js")}

var varStatus = '{!Interview__c.InterviewStatus__c}';


var result = sforce.apex.execute(
  'SFTR_O_InterviewWebService',
  'release',
  {itemId:'{!Interview__c.Id}'}
);

if(result == '成功'){
	location.reload();
} else if (result == 'チェック失敗') {
	alert('実行できません!');
}else {
	alert('公開が失敗してしまった');
}
